func tryExec() error {
	switch runtime.GOOS {
	case "wasip1", "js", "ios":
	default:

		return nil
	}

	if !testing.Testing() {

		return errors.New("can't probe for exec support with a non-test executable")
	}

	exe, err := os.Executable()
	if err != nil {
		return fmt.Errorf("can't probe for exec support: %w", err)
	}
	cmd := exec.Command(exe, "-test.list=^$")
	cmd.Env = origEnv
	return cmd.Run()
}
